module TopModule (
    input [7:0] A,
    input [7:0] B,
    output reg [7:0] S,
    output reg C_out,
    output reg V
);
    wire [8:0] temp_sum;

    always @(*) begin
        temp_sum = {1'b0, A} + {1'b0, B};
        S = temp_sum[7:0];
        C_out = temp_sum[8];
        V = (A[7] == B[7]) && (A[7] != S[7]);
    end
endmodule

